#!/usr/bin/env node
/**
 * Delete gallery images from a list and preserve their hashes in pull-state.json
 * so they won't be re-imported.
 *
 * Usage:
 *   node scripts/whatsapp-gallery/delete-selected.mjs <list-file> [--dry-run]
 *
 * The list file should contain one path per line, relative to the repo root:
 *   public/images/gallery/2025/12/estebike_001_Mario.jpg
 *   public/images/gallery/2026/01/estebike_003_unknown.jpg
 *
 * Generated by the gallery edit mode: /galleria?edit=true
 */

import fs from "fs";
import path from "path";
import crypto from "crypto";

const ROOT = path.resolve(import.meta.dirname, "../..");
const STATE_PATH = path.join(ROOT, "scripts/whatsapp-gallery/pull-state.json");
const DESC_PATH = path.join(ROOT, "scripts/whatsapp-gallery/descriptions.json");

const DRY_RUN = process.argv.includes("--dry-run");
const LIST_FILE = process.argv[2];

if (!LIST_FILE || LIST_FILE.startsWith("--")) {
  console.error(
    "Usage: node delete-selected.mjs <list-file> [--dry-run]\n" +
    "       list-file: one image path per line (relative to repo root)"
  );
  process.exit(1);
}

const lines = fs
  .readFileSync(LIST_FILE, "utf8")
  .split("\n")
  .map((l) => l.trim())
  .filter((l) => l && !l.startsWith("#"));

if (lines.length === 0) {
  console.log("No images in the list.");
  process.exit(0);
}

const state = JSON.parse(fs.readFileSync(STATE_PATH, "utf8"));
const knownHashes = new Set(state.known_hashes || []);

let descriptions = {};
try {
  descriptions = JSON.parse(fs.readFileSync(DESC_PATH, "utf8"));
} catch { /* empty */ }

let deleted = 0;
let notFound = 0;
let alreadyHashed = 0;

for (const rel of lines) {
  const abs = path.resolve(ROOT, rel);
  if (!fs.existsSync(abs)) {
    console.warn(`  SKIP (not found): ${rel}`);
    notFound++;
    continue;
  }

  // Hash the file before deleting
  const buf = fs.readFileSync(abs);
  const hash = "\\" + crypto.createHash("md5").update(buf).digest("hex");

  if (knownHashes.has(hash)) {
    alreadyHashed++;
  }
  knownHashes.add(hash);

  // Remove description entry
  const filename = path.basename(abs);
  if (descriptions[filename]) {
    delete descriptions[filename];
  }

  if (!DRY_RUN) {
    fs.unlinkSync(abs);
  }
  deleted++;
  console.log(`  ${DRY_RUN ? "WOULD DELETE" : "DELETED"}: ${rel}`);
}

// Update state
if (!DRY_RUN) {
  state.known_hashes = [...knownHashes].sort();
  fs.writeFileSync(STATE_PATH, JSON.stringify(state, null, 2));

  const comment = descriptions._comment;
  delete descriptions._comment;
  const sorted = {
    _comment: comment || "Maps image filename to Italian alt text.",
    ...descriptions,
  };
  fs.writeFileSync(DESC_PATH, JSON.stringify(sorted, null, 2));
}

console.log(`\n${"═".repeat(40)}`);
console.log(`  Deleted:        ${deleted}`);
console.log(`  Not found:      ${notFound}`);
console.log(`  Already hashed: ${alreadyHashed}`);
console.log(`  New hashes:     ${deleted - alreadyHashed}`);
if (DRY_RUN) console.log("\n  !! DRY RUN — no files were modified.");
